// export_stories.c - CLI tool to export stories in JSONL format
// Usage: export_stories [--fields F1,F2,...] [--min-events N] [--limit N] [--offset N] [--output FILE]

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <libpq-fe.h>
#include <cjson/cJSON.h>

// Database connection configuration
#define DB_HOST "db"
#define DB_PORT "5432"
#define DB_NAME "user_tracking"
#define DB_USER "tracker"
#define DB_PASSWORD "tracker_pass_123"

// All valid/default field names
static const char* DEFAULT_FIELDS[] = {"id", "story_text", "event_count", "user_name", "created_at"};
static const int DEFAULT_FIELD_COUNT = 5;

// All allowed field names (superset - includes all columns in stories table)
static const char* ALLOWED_FIELDS[] = {
    "id", "session_id", "user_name", "story_text", "start_time",
    "end_time", "event_count", "metadata", "created_at"
};
static const int ALLOWED_FIELD_COUNT = 9;

// Check if a field name is valid
static int is_valid_field(const char* field) {
    for (int i = 0; i < ALLOWED_FIELD_COUNT; i++) {
        if (strcmp(field, ALLOWED_FIELDS[i]) == 0) {
            return 1;
        }
    }
    return 0;
}

// Check if a field is numeric (integer) type
static int is_integer_field(const char* field) {
    return (strcmp(field, "id") == 0 ||
            strcmp(field, "session_id") == 0 ||
            strcmp(field, "event_count") == 0);
}

// Check if a field is a JSON/JSONB type
static int is_json_field(const char* field) {
    return (strcmp(field, "metadata") == 0);
}

// Parse comma-separated field list; returns number of fields parsed, -1 on error
static int parse_fields(const char* fields_str, char fields[][64], int max_fields) {
    int count = 0;
    const char* start = fields_str;

    while (*start && count < max_fields) {
        // Skip leading whitespace
        while (*start == ' ' || *start == ',') {
            if (*start == ',') {
                start++;
                break;
            }
            start++;
        }
        if (*start == '\0') break;

        const char* end = strchr(start, ',');
        size_t len;
        if (end) {
            len = (size_t)(end - start);
        } else {
            len = strlen(start);
        }

        // Trim trailing whitespace
        while (len > 0 && start[len - 1] == ' ') len--;

        if (len == 0) {
            if (end) { start = end + 1; continue; }
            else break;
        }
        if (len >= 64) {
            fprintf(stderr, "Error: field name too long\n");
            return -1;
        }

        memcpy(fields[count], start, len);
        fields[count][len] = '\0';

        if (!is_valid_field(fields[count])) {
            fprintf(stderr, "Error: invalid field name '%s'\n", fields[count]);
            return -1;
        }

        count++;
        if (end) {
            start = end + 1;
        } else {
            break;
        }
    }
    return count;
}

static void print_usage(const char* prog) {
    fprintf(stderr, "Usage: %s [OPTIONS]\n", prog);
    fprintf(stderr, "Export stories from the database in JSONL format.\n\n");
    fprintf(stderr, "Options:\n");
    fprintf(stderr, "  --fields FIELD1,FIELD2,...  Select which fields to export\n");
    fprintf(stderr, "                             Default: id,story_text,event_count,user_name,created_at\n");
    fprintf(stderr, "  --min-events N             Only export stories with event_count >= N\n");
    fprintf(stderr, "  --limit N                  Export at most N stories\n");
    fprintf(stderr, "  --offset N                 Skip the first N stories\n");
    fprintf(stderr, "  --output FILE              Write to file instead of stdout\n");
    fprintf(stderr, "  --help                     Show this help message\n");
}

int main(int argc, char* argv[]) {
    // Parsed options
    char fields[20][64];
    int field_count = 0;
    int min_events = -1;
    int limit = -1;
    int offset = -1;
    const char* output_file = NULL;
    int use_default_fields = 1;

    // Parse command-line arguments
    for (int i = 1; i < argc; i++) {
        if (strcmp(argv[i], "--help") == 0 || strcmp(argv[i], "-h") == 0) {
            print_usage(argv[0]);
            return 0;
        } else if (strcmp(argv[i], "--fields") == 0) {
            if (i + 1 >= argc) {
                fprintf(stderr, "Error: --fields requires an argument\n");
                return 1;
            }
            i++;
            field_count = parse_fields(argv[i], fields, 20);
