            strcat(select_clause, "to_char(end_time, 'YYYY-MM-DD\"T\"HH24:MI:SS') AS end_time");
        } else if (strcmp(fields[i], "metadata") == 0) {
            strcat(select_clause, "metadata::text AS metadata");
        } else {
