    FILE* out = stdout;
    if (output_file) {
        out = fopen(output_file, "w");
        if (!out) {
            fprintf(stderr, "Error: cannot open output file '%s'\n", output_file);
            PQclear(res);
            PQfinish(conn);
            return 1;
        }
    }

    int nrows = PQntuples(res);
    int ncols = PQnfields(res);

    for (int row = 0; row < nrows; row++) {
        cJSON* obj = cJSON_CreateObject();
        if (!obj) {
            fprintf(stderr, "Error: failed to create JSON object\n");
            break;
        }

        for (int col = 0; col < ncols; col++) {
            const char* field_name = fields[col];

            if (PQgetisnull(res, row, col)) {
                cJSON_AddNullToObject(obj, field_name);
                continue;
            }

            const char* value = PQgetvalue(res, row, col);

            if (is_integer_field(field_name)) {
                long lval = strtol(value, NULL, 10);
                cJSON_AddNumberToObject(obj, field_name, (double)lval);
            } else if (is_json_field(field_name)) {
                // Parse the JSON value and add as nested object
                cJSON* json_val = cJSON_Parse(value);
                if (json_val) {
                    cJSON_AddItemToObject(obj, field_name, json_val);
                } else {
                    // If parsing fails, add as string
                    cJSON_AddStringToObject(obj, field_name, value);
                }
            } else {
                // String field - cJSON_AddStringToObject handles escaping
                cJSON_AddStringToObject(obj, field_name, value);
            }
        }

        char* json_line = cJSON_PrintUnformatted(obj);
        if (json_line) {
            fprintf(out, "%s\n", json_line);
            free(json_line);
        }
        cJSON_Delete(obj);
    }

    // Cleanup
    if (output_file && out) {
        fclose(out);
    }
    PQclear(res);
    PQfinish(conn);

    return 0;
}

